513	            root.join(".lock"),
514	            LockedFileMode::Shared,
515	            root.simplified_display(),
516	        ) else {
517	            return Ok(None);
518	        };
519	        Ok(Some(Self {
520	            root: std::path::absolute(root).map_err(Error::Absolute)?,
521	            lock_file: Some(Arc::new(lock_file)),
522	            ..self
523	        }))
