621	                    debug!("Removing dangling cache environment: {}", path.display());
622	                    summary += rm_rf(path)?;
623	                }
624	            }
625	            Err(err) if err.kind() == io::ErrorKind::NotFound => (),
626	            Err(err) => return Err(err),
627	        }
