632	            match fs_err::read_dir(self.bucket(CacheBucket::Wheels)) {
633	                Ok(entries) => {
634	                    for entry in entries {
635	                        let entry = entry?;
636	                        let path = fs_err::canonicalize(entry.path())?;
637	                        if path.is_dir() {
638	                            debug!("Removing unzipped wheel entry: {}", path.display());
