12	/// Display a per-bucket breakdown of cache usage, followed by the total.
13	pub(crate) fn cache_stats(
14	    cache: &Cache,
15	    human_readable: bool,
16	    printer: Printer,
17	    preview: Preview,
18	) -> Result<ExitStatus> {
19	    if !preview.is_enabled(PreviewFeature::CacheSize) {
