21	            "`uv cache stats` is experimental and may change without warning. Pass `--preview-features {}` to disable this warning.",
22	            PreviewFeature::CacheSize
23	        );
24	    }
25	
26	    if !cache.root().exists() {
27	        for bucket in CacheBucket::iter() {
28	            if human_readable {
29	                writeln!(printer.stdout_important(), "{}: 0B", bucket.display_name())?;
30	            } else {
31	                writeln!(printer.stdout_important(), "{}: 0", bucket.display_name())?;
32	            }
33	        }
34	        if human_readable {
